// SPDX-License-Identifier: GPL-2.0-or-later\n// SPDX-FileCopyrightText: 2025-2026 PS4 Nexus Emulator Project\n\n#include \"instruction_decoder.hpp\"\n#include \"../common/logger.hpp\"\n\nnamespace PS4Nexus::CPU {\n\nInstruction InstructionDecoder::Decode(uint64_t addr, const std::vector<uint8_t>& code) {\n    Instruction instr;\n    instr.address = addr;\n    instr.length = GetInstructionSize(code);\n    \n    if (instr.length > 0 && instr.length <= code.size()) {\n        instr.bytes.insert(instr.bytes.end(), \n                          code.begin(), \n                          code.begin() + instr.length);\n    }\n    \n    return instr;\n}\n\nuint32_t InstructionDecoder::GetInstructionSize(const std::vector<uint8_t>& code) {\n    if (code.empty()) return 0;\n    \n    uint8_t first_byte = code[0];\n    \n    if ((first_byte & 0xF0) == 0x40) return 2;\n    if ((first_byte & 0xC0) == 0xC0) return 3;\n    \n    return 1;\n}\n\nstd::string InstructionDecoder::DisassembleInstruction(const Instruction& instr) {\n    return instr.mnemonic + \" \" + (instr.operands.empty() ? \"\" : instr.operands[0]);\n}\n\n} // namespace PS4Nexus::CPU\n